This Python code has a race condition. Identify it, explain
why it's dangerous, and fix it:

import threading

counter = 0

def increment():
    global counter
    for _ in range(100000):
        counter += 1

threads = [threading.Thread(target=increment) for _ in range(4)]
for t in threads: t.start()
for t in threads: t.join()
print(counter)

This function does too many things. Refactor it into smaller,
well-named functions and explain your reasoning:

def process_order(order):
    if order['quantity'] <= 0:
        return {'error': 'Invalid quantity'}
    subtotal = order['price'] * order['quantity']
    if order.get('coupon') == 'SAVE10':
        subtotal *= 0.9
    tax = subtotal * 0.08
    total = subtotal + tax
    if order.get('email'):
        print(f"Sending receipt to {order['email']}")
    return {'subtotal': subtotal, 'tax': tax, 'total': total}
